import{_ as t,o as l,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"F11: 處分重大資產與資本配置 - 財務審計專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3105_穩懋/20260503/F11_處分重大資產與資本配置.md","filePath":"審計報告庫/財務審計/3105_穩懋/20260503/F11_處分重大資產與資本配置.md"}'),e={name:"審計報告庫/財務審計/3105_穩懋/20260503/F11_處分重大資產與資本配置.md"};function i(n,a,s,h,T,N){return l(),r("div",null,[...a[0]||(a[0]=[o('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f11-處分重大資產與資本配置-財務審計專家-審計報告" tabindex="-1">F11: 處分重大資產與資本配置 - 財務審計專家 審計報告 <a class="header-anchor" href="#f11-處分重大資產與資本配置-財務審計專家-審計報告" aria-label="Permalink to &quot;F11: 處分重大資產與資本配置 - 財務審計專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>是否存在處分重大資產之行為？處分損益佔比為何？資金用途是投入再投資還是為了彌補虧損？</p></blockquote><h2 id="🎯-專家直斷-62-字" tabindex="-1">🎯 專家直斷（62 字） <a class="header-anchor" href="#🎯-專家直斷-62-字" aria-label="Permalink to &quot;🎯 專家直斷（62 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：2025 年處分 PP&amp;E 利得 NT$1.95B（佔稅前 60.4%），屬近年最大規模資產活化。資金主要用於償債（償還長借 NT$7.99B）而非再投資，屬「防禦型配置」非「成長型配置」。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至 2025 年最新公開數據</li></ul><h2 id="📊-診斷評級-127-字" tabindex="-1">📊 診斷評級（127 字） <a class="header-anchor" href="#📊-診斷評級-127-字" aria-label="Permalink to &quot;📊 診斷評級（127 字）&quot;">​</a></h2><ul><li><strong>重點數據</strong>：2025 年處分 PP&amp;E 利得 NT$1,953M（佔稅前淨利 60.4%，佔 NI 57.4%）。對應減損損失 NT$1,642M，兩者對沖後淨貢獻 NT$311M。2025 年 CapEx NT$697M 遠低於折舊 NT$3,907M。償還長借 NT$7,993M。股利發放 NT$1.0/股（總 NT$424M）。對比 2024 年處分 PP&amp;E 損失 NT$17M（無重大處分）。</li><li><strong>診斷見解</strong>：處分利益為一次性，對沖減損後淨貢獻有限。資金去向明確為去槓桿（償債 NT$7.99B），非投入擴產。整體屬清理非核心資產（推測農牧用地/閒置廠房）的財務體質調整，非業務萎縮。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="獲利含金量穿透" tabindex="-1">獲利含金量穿透 <a class="header-anchor" href="#獲利含金量穿透" aria-label="Permalink to &quot;獲利含金量穿透&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2025 年稅前淨利 NT$1,387M 中，處分 PP&amp;E 利得 NT$1,953M 佔比 140.8%（如扣除減損損失 NT$1,642M 後淨佔比 22.4%）。扣除非經常性損益後，核心稅前淨利約 NT$1,076M（稅後約 NT$850M），核心 EPS 約 NT$2.0。帳面 EPS NT$4.00 中一次性貢獻約 NT$0.7-1.0。</li><li><strong>深度見解</strong>：處分規模為三年最大，但與減損損失幾乎對沖，實際對現金流貢獻有限（處分現金流入已反映於投資活動現金流 NT$5.1B）。</li></ul><h3 id="戰略意圖判別" tabindex="-1">戰略意圖判別 <a class="header-anchor" href="#戰略意圖判別" aria-label="Permalink to &quot;戰略意圖判別&quot;">​</a></h3><ul><li><strong>核心重點</strong>：資金主要去向：償還長期借款 NT$7,993M（CFO NT$4,953M+處分收入），使長借從 NT$16.5B 降至 NT$12.3B。非投入 CapEx 或研發。去槓桿後利息支出從 NT$795M→NT$675M（-15.1%），年省 NT$120M。</li><li><strong>深度見解</strong>：此為防禦型資本配置——資產活化→償債→降低財務風險。對 ROE 有正面效果（權益不變、負債減少）。惟若無新的成長型投資，長期營收成長動能將受限。</li></ul><h3 id="資產結構變動" tabindex="-1">資產結構變動 <a class="header-anchor" href="#資產結構變動" aria-label="Permalink to &quot;資產結構變動&quot;">​</a></h3><ul><li><strong>核心重點</strong>：PP&amp;E 淨額 NT$31.3B→NT$19.7B（-37%），總資產 NT$69.2B→NT$60.7B（-12%）。ROA 從 -0.1% 升至 1.8%，ROE 從 -0.3% 升至 2.6%。</li><li><strong>深度見解</strong>：資產效率指標改善，但主因為分母縮減（資產減少）而非分子擴張（獲利成長）。實質營運效率未見系統性提升。</li></ul><h2 id="💡-專家評析-≥2-個利空關鍵字" tabindex="-1">💡 專家評析（≥2 個利空關鍵字） <a class="header-anchor" href="#💡-專家評析-≥2-個利空關鍵字" aria-label="Permalink to &quot;💡 專家評析（≥2 個利空關鍵字）&quot;">​</a></h2><ol><li><p><strong>處分利益一次性、不可持續，獲利質量打折</strong>：NT$1.95B 處分利得佔稅前 60.4% 且一次沖銷 NT$1.64B 減損。淨貢獻僅 NT$311M（稅前 22.4%）。若剔除處分利得，2025 年核心 EPS 僅 NT$2.0-2.5，帳面 EPS NT$4.00 有明顯虛胖風險。2024 年無此類收益（僅 NT$17M 處分損失）。</p></li><li><p><strong>資產清理後再投資動能不足</strong>：處分資金用於償債而非擴產，CapEx NT$697M 為歷史低點。當 GaAs 產業轉向 6 吋 InP/HBT 先進製程時，穩懋的設備更新能否跟上競爭者（三安集成、宏捷科）存疑。若無新廠投資計劃，3-5 年後可能面臨製程落後、客戶轉單的競爭壓力。</p></li><li><p><strong>農牧部門持續虧損 NT$1.17B，資產活化尚未解決核心問題</strong>：農牧科技部門虧損 NT$1.17B 幾乎吃掉晶圓代工部門利潤 NT$1.91B 的 61%，處分農牧用地雖有助短期一次性收益，但未能解決該部門結構性虧損。管理層若持續持有此非核心虧損業務，將繼續侵蝕本業獲利。</p></li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：數據採集器.py (finance 3105)、(cash_flow 3105)</li><li>原始數據：FinMind TaiwanStockFinancialStatements、TaiwanStockCashFlowsStatement</li><li>年報 PDF：2025_Q4_3105_合併.pdf（業外附註 p.57-60、PP&amp;E 明細 p.43）</li><li>關鍵核對碼：處分 PP&amp;E 利得 NT$1,953,270K, 減損損失 NT$1,641,913K, 償還長借 NT$7,993,043K</li></ul>',19)])])}const d=t(e,[["render",i]]);export{_ as __pageData,d as default};
